const PDFDocument = require('pdfkit');
const Bill = require('../models/Bill'); // adjust path if needed

exports.generatePDF = async (req, res) => {
  try {
    const { billId } = req.params;
    const bill = await Bill.findById(billId);

    if (!bill) {
      return res.status(404).json({ success: false, message: 'Bill not found' });
    }

    const doc = new PDFDocument({ margin: 40 });
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader(
      'Content-Disposition',
      `inline; filename=bill-${billId}.pdf`
    );

    doc.pipe(res);

    /* ================= HEADER ================= */

    doc
      .fontSize(22)
      .font('Helvetica-Bold')
      .text('URBAN THREADS', { align: 'center' });

    doc
      .fontSize(10)
      .font('Helvetica')
      .text('Premium Clothing Store', { align: 'center' });

    doc
      .text('MG Road, Pune – 411001', { align: 'center' })
      .text('GSTIN: 27ABCDE1234F1Z5', { align: 'center' })
      .moveDown(1);

    doc
      .moveTo(40, doc.y)
      .lineTo(550, doc.y)
      .stroke();

    /* ================= BILL INFO ================= */

    doc.moveDown(1);
    doc.fontSize(10);

    doc.text(`Bill No: ${bill._id}`);
    doc.text(`Date: ${new Date(bill.createdAt).toLocaleString()}`);
    doc.moveDown(1);

    /* ================= TABLE HEADER ================= */

    const tableTop = doc.y + 10;

    doc.font('Helvetica-Bold');
    doc.text('Item', 40, tableTop);
    doc.text('SKU', 220, tableTop);
    doc.text('Qty', 320, tableTop, { width: 40, align: 'right' });
    doc.text('Rate', 380, tableTop, { width: 60, align: 'right' });
    doc.text('Amount', 460, tableTop, { width: 80, align: 'right' });

    doc.moveTo(40, tableTop + 15).lineTo(550, tableTop + 15).stroke();

    /* ================= TABLE ROWS ================= */

    doc.font('Helvetica');
    let y = tableTop + 25;

    bill.items.forEach((item) => {
      doc.text(item.name, 40, y, { width: 170 });
      doc.text(item.productId, 220, y);
      doc.text(item.qty, 320, y, { width: 40, align: 'right' });
      doc.text(item.price.toFixed(2), 380, y, { width: 60, align: 'right' });
      doc.text(
        (item.qty * item.price).toFixed(2),
        460,
        y,
        { width: 80, align: 'right' }
      );
      y += 20;
    });

    /* ================= TOTALS ================= */

    y += 10;
    doc.moveTo(300, y).lineTo(550, y).stroke();
    y += 10;

    doc.font('Helvetica-Bold');
    doc.text('Subtotal:', 380, y, { width: 90, align: 'right' });
    doc.text(bill.subtotal.toFixed(2), 460, y, { width: 80, align: 'right' });

    y += 18;
    doc.font('Helvetica');
    doc.text('Discount:', 380, y, { width: 90, align: 'right' });
    doc.text(
      `- ${bill.discountAmount.toFixed(2)}`,
      460,
      y,
      { width: 80, align: 'right' }
    );

    y += 20;
    doc.font('Helvetica-Bold');
    doc.text('Grand Total:', 380, y, { width: 90, align: 'right' });
    doc.text(
      bill.totalAmount.toFixed(2),
      460,
      y,
      { width: 80, align: 'right' }
    );

    /* ================= FOOTER ================= */

    doc.moveDown(3);
    doc
      .fontSize(10)
      .font('Helvetica')
      .text('Thank you for shopping with us!', { align: 'center' });

    doc
      .text('Exchange within 7 days with original bill.', {
        align: 'center'
      })
      .text('This is a computer-generated bill.', {
        align: 'center'
      });

    doc.end();
  } catch (error) {
    console.error(error);
    res.status(500).json({
      success: false,
      message: 'Failed to generate PDF'
    });
  }
};
